mapper.select:
select u.id,u.username,u.name,u.phone,u.email,u.dept,u.status,u.last_login_time,u.remark,
       u.create_time,u.update_time,u.deleted,r.name as roleName
from user u left join user_role ur on u.id = ur.user_id left join role r on ur.role_id = r.id


        and u.name like concat('%',#{q.name},'%')


        and r.name = #{q.roleName}


        and u.dept = #{q.dept}


        and u.status = #{q.status}
